#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

uint64_t powmod(uint64_t base, uint64_t exponent) {
    uint64_t result = 1;
    while (exponent > 0) {
        if (exponent & 1) {
            result = (result * base) % MOD;
        }
        exponent >>= 1;
        base = (base * base) % MOD;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        uint64_t N, K;
        scanf("%llu %llu", &N, &K);
        uint64_t result = K;
        for (uint64_t i = 1; i < N; i++) {
            result = (result * (K - 1)) % MOD;
        }
        printf("%llu\n", result);
    }
    return 0;
}

